/** O(1) lookup by familyId */
export const FAMILY_MAP: Map<string, OmegaFamily> = new Map(
  ALL_FAMILIES.map(f => [f.familyId, f])
);

/** Array of all familyIds */
export const ALL_FAMILY_IDS: string[] = ALL_FAMILIES.map(f => f.familyId);

/** CORPORATIONS format — for publication-engine compatibility */
export const CORPORATIONS_FROM_FAMILIES: Record<string, {
  name: string; tagline: string; sector: string; color: string; emoji: string; major: string;
}> = Object.fromEntries(
  ALL_FAMILIES.map(f => [f.familyId, {
    name: f.name, tagline: f.tagline, sector: f.sector,
    color: f.color, emoji: f.emoji, major: f.major,
  }])
);

/** OMEGA_SOURCES format — for spawn-engine compatibility */
export const OMEGA_SOURCES_FROM_FAMILIES: {
  familyId: string; businessId: string; domain: string; description: string;
  color: string; emoji: string; megaDomain: string; sources: string[];
  nodeCount: number; priority: number;
}[] = ALL_FAMILIES.map(f => ({
  familyId: f.familyId,
  businessId: f.name,
  domain: f.domain,
  description: f.description,
  color: f.color,
  emoji: f.emoji,
  megaDomain: f.megaDomain,
  sources: f.sources,
  nodeCount: f.nodeCount,
  priority: f.priority,
}));

