export function resolveFamily(text: string): string {
  for (const [re, fam] of GICS_FAMILY_REGEX) {
    if (re.test(text)) return fam;
  }
  return "knowledge";
}

export function getFamily(familyId: string): OmegaFamily {
  return FAMILY_MAP.get(familyId) || FAMILY_MAP.get("knowledge")!;
}

